if (!function_exists('v3_customer_code_dn')) {
    function v3_customer_code_dn($code='', $id=0){
        $code=strtoupper(trim((string)$code));
        $code=preg_replace('/\s+/','',$code);
        $code=preg_replace('/[^A-Z0-9]/','',$code);
        if($code!=='' && strpos($code,'DN')!==0) $code='DN'.$code;
        if($code!=='' && preg_match('/^DN\d{10}$/',$code)) return $code;
        for($i=0;$i<60;$i++){
            $candidate='DN'.str_pad((string)random_int(0,9999999999),10,'0',STR_PAD_LEFT);
            $exists=q1('SELECT id FROM customers WHERE customer_code=? AND id<>? LIMIT 1',[$candidate,(int)$id]);
            if(!$exists) return $candidate;
        }
        throw new Exception('Gagal membuat ID pelanggan unik. Coba simpan ulang.');
    }
}
