function filter_form($extra=''){ global $month,$q,$per,$page,$dataHealth; $healthHidden=$dataHealth!==''?'<input type="hidden" name="data_health" value="'.e($dataHealth).'">':''; echo '<form class="form-inline ajax-search-form search-command-bar" autocomplete="off"><input type="hidden" name="page" value="'.e($page).'">'.$healthHidden.'<div class="search-command-title"><span class="search-command-icon"><i class="fas fa-search"></i></span><div><b>Pencarian cepat</b><small>Ketik ID, nama, alamat, telepon, username, atau Secret.</small></div></div><div class="form-group month-filter"><label>Bulan</label><input class="form-control" type="month" name="month" value="'.e($month).'"></div><div class="form-group search-wide search-field-shell"><label>Cari real-time</label><div class="search-input-wrap"><i class="fas fa-magnifying-glass"></i><input class="form-control ajax-search-input" name="q" value="'.e($q).'" placeholder="Contoh: DN123, nama pelanggan, alamat, telepon, username, Secret"></div></div><div class="form-group per-filter"><label>Tampil</label><select class="form-control" name="per"><option '.($per==10?'selected':'').'>10</option><option '.($per==25?'selected':'').'>25</option><option '.($per==50?'selected':'').'>50</option><option '.($per==100?'selected':'').'>100</option></select></div>'.$extra.'<div class="search-actions"><button class="btn btn-info search-submit"><i class="fas fa-filter"></i> Terapkan</button><a class="btn btn-secondary ajax-reset" href="index.php?page='.e($page).'"><i class="fas fa-rotate-left"></i> Reset</a></div><span class="ajax-hint"><i class="fas fa-bolt"></i> Real-time tanpa Enter</span></form>'; }
function customer_year_filter(){
    global $year;
    $current=(int)date('Y');
    $existing=qall("SELECT DISTINCT substr(registered_at,1,4) y FROM customers WHERE registered_at<>'' AND substr(registered_at,1,4) GLOB '[0-9][0-9][0-9][0-9]' ORDER BY y DESC");
    $years=[];
    foreach($existing as $r){ $y=(int)$r['y']; if($y>=2000 && $y<=2100) $years[$y]=true; }
    for($y=$current+3;$y>=2010;$y--) $years[$y]=true;
    if($year!=='' && preg_match('/^\d{4}$/',$year)) $years[(int)$year]=true;
    $list=array_keys($years); rsort($list,SORT_NUMERIC);
    $html='<div class="form-group year-flex"><label>Tahun Registrasi</label><div class="year-flex-row"><select class="form-control year-select" name="year"><option value="">Semua Tahun</option>';
    foreach($list as $y){ $ys=(string)$y; $html.='<option value="'.e($ys).'" '.($year===$ys?'selected':'').'>'.e($ys).'</option>'; }
    $html.='</select><input class="form-control year-manual" inputmode="numeric" pattern="[0-9]{4}" maxlength="4" placeholder="manual" value="'.e($year).'"></div><small class="text-muted">Tahun fleksibel, bisa mundur/maju. Isi manual kalau tahun belum ada di daftar.</small></div>';
    return $html;
}
function pager($total,$page,$pages,$params=[]){ if($pages<=1){ echo '<div class="pager-shell"><div class="pager-info">Total '.(int)$total.' data</div></div>'; return; } $base=array_merge($_GET,$params); echo '<div class="pager-shell"><div class="pager-info">Halaman '.(int)$page.' dari '.(int)$pages.' · Total '.(int)$total.' data</div><div class="pagination smart-pagination">'; $mk=function($label,$target,$disabled=false,$active=false) use ($base){ $url='index.php?'.http_build_query(array_merge($base,['p'=>$target])); echo '<a class="'.($disabled?'disabled ':'').($active?'active ':'').'" href="'.e($url).'">'.$label.'</a>'; }; $mk('&laquo;',1,$page<=1); $mk('&lsaquo;',max(1,$page-1),$page<=1); $window=[]; foreach([1,2,$page-2,$page-1,$page,$page+1,$page+2,$pages-1,$pages] as $i){ if($i>=1 && $i<=$pages) $window[$i]=true; } $last=0; foreach(array_keys($window) as $i){ if($last && $i>$last+1) echo '<span class="ellipsis">...</span>'; $mk((string)$i,$i,false,$i==$page); $last=$i; } $mk('&rsaquo;',min($pages,$page+1),$page>=$pages); $mk('&raquo;',$pages,$page>=$pages); echo '</div></div>'; }
