function customer_buttons($r){
    $id=(int)($r['id']??$r); $status=$r['customer_status']??'active'; $price=(int)($r['price']??0);
    $hasLoc=!empty($r['latitude']) && !empty($r['longitude']) && is_numeric($r['latitude']) && is_numeric($r['longitude']);
    if(current_user_is_crew()){
        return $hasLoc
            ? '<a class="btn btn-primary btn-sm" target="_blank" rel="noopener noreferrer" href="'.e(v3_google_maps_url($r['latitude'],$r['longitude'])).'"><i class="fas fa-map-marker-alt"></i> Buka Lokasi</a>'
            : '<span class="text-muted">Lokasi belum tersedia</span>';
    }
    $html='<div class="customer-actions action-stack-v3">';
    $html.='<a class="btn btn-success btn-sm" href="index.php?page=add-laporan-ipl&customer_id='.$id.'">Bayar</a>';
    $html.='<a class="btn btn-warning btn-sm" href="detail.php?id='.$id.'">Detail</a>';
    $html.='<a class="btn btn-info btn-sm" href="edit.php?type=customer&id='.$id.'">Edit</a>';
    if($hasLoc){ $html.='<a class="btn btn-primary btn-sm" target="_blank" href="'.e(v3_google_maps_url($r['latitude'],$r['longitude'])).'">Lokasi</a>'; }
    $html.='<div class="action-menu"><button type="button" class="btn btn-light btn-sm action-menu-toggle">Kelola <span>▾</span></button><div class="action-menu-panel"><div class="action-menu-caption">Aksi status pelanggan</div>';
    if($status==='active'){
        $html.=customer_quick_form($id,'off','Pindahkan ke OFF','text-danger','Pindahkan pelanggan ini ke OFF?');
        if($price>0) $html.=customer_quick_form($id,'free','Jadikan FREE / Gratis','text-info','Jadikan pelanggan FREE / Gratis? Paket akan dipindah ke paket Rp0 aktif.');
        $html.=customer_quick_form($id,'isolir','Tandai isolir','text-warning','Tandai pelanggan ini isolir?');
    } else {
        $html.=customer_quick_form($id,'active','Aktifkan lagi','text-success','Aktifkan pelanggan ini lagi?');
    }
    $html.='<div class="dropdown-divider"></div>'.customer_delete_item($id).'</div></div></div>';
    return $html;
}
