function base_customer_where(&$params){ global $q,$year,$page,$dataHealth; $where='1=1'; if($page==='data-warga'){ if($dataHealth==='') $where.=" AND c.customer_status='active' AND COALESCE(c.is_active,1)=1 AND COALESCE(pk.price,0)>0"; if($dataHealth==='missing_address') $where.=" AND c.customer_status='active' AND COALESCE(c.is_active,1)=1 AND length(trim(COALESCE(c.address,'')))<8"; elseif($dataHealth==='missing_secret') $where.=" AND c.customer_status<>'off' AND length(trim(COALESCE(c.onu_name,'')))=0"; elseif($dataHealth==='missing_coordinate') $where.=" AND c.customer_status='active' AND COALESCE(c.is_active,1)=1 AND (c.latitude IS NULL OR c.longitude IS NULL OR trim(CAST(c.latitude AS TEXT))='' OR trim(CAST(c.longitude AS TEXT))='')"; } if($q!==''){ $where.=' AND (c.customer_code LIKE ? OR c.name LIKE ? OR c.address LIKE ? OR c.phone LIKE ? OR c.area_name LIKE ? OR c.pppoe_username LIKE ? OR c.onu_name LIKE ?)'; for($i=0;$i<7;$i++)$params[]='%'.$q.'%'; } if($page==='data-warga' && $year!==''){ $where.=' AND substr(c.registered_at,1,4)=?'; $params[]=$year; } return $where; }
function data_health_filter_notice(){ global $dataHealth; if($dataHealth==='') return; $labels=['missing_address'=>['Alamat belum lengkap','Menampilkan pelanggan aktif yang alamatnya belum lengkap. Pelanggan OFF / Tidak aktif tidak dihitung. Klik Detail/Edit untuk melengkapi data.'],'missing_secret'=>['Secret pelanggan belum terisi','Menampilkan pelanggan non-OFF yang field Secret / ONU masih kosong. Pelanggan OFF / Tidak aktif tidak dihitung. Klik Detail/Edit untuk melengkapi Secret.'],'missing_coordinate'=>['Titik koordinat belum terisi','Menampilkan pelanggan aktif yang Tikor latitude/longitude belum tersimpan. Pelanggan OFF / Tidak aktif tidak dihitung. Klik Detail/Edit untuk mengisi koordinat.']]; $m=$labels[$dataHealth]??null; if(!$m) return; echo '<div class="alert alert-warning"><b>'.e($m[0]).'</b><br>'.e($m[1]).' <a class="btn btn-sm btn-light ml-2" href="'.page_url('data-warga').'">Lihat pelanggan aktif berbayar</a></div>'; }
function customer_rows($extraWhere='', $extraParams=[]){ global $p,$per; $params=[]; $where=base_customer_where($params); if($extraWhere){$where.=' '.$extraWhere; $params=array_merge($params,$extraParams);} $total=(int)scalar("SELECT COUNT(*) FROM customers c LEFT JOIN packages pk ON pk.id=c.package_id WHERE $where",$params); [$page,$pages,$off]=paginate($total,$p,$per); $rows=qall("SELECT c.*,pk.name package_name,pk.speed,pk.price,(SELECT pay.paid_at FROM payments pay WHERE pay.customer_id=c.id ORDER BY datetime(pay.paid_at) DESC,pay.id DESC LIMIT 1) last_paid,(SELECT pay.amount FROM payments pay WHERE pay.customer_id=c.id ORDER BY datetime(pay.paid_at) DESC,pay.id DESC LIMIT 1) last_paid_amount,(SELECT pay.invoice_month FROM payments pay WHERE pay.customer_id=c.id ORDER BY datetime(pay.paid_at) DESC,pay.id DESC LIMIT 1) last_paid_month,(SELECT pay.method FROM payments pay WHERE pay.customer_id=c.id ORDER BY datetime(pay.paid_at) DESC,pay.id DESC LIMIT 1) last_paid_method,COALESCE(c.points_balance,(SELECT COALESCE(SUM(cp.points),0) FROM customer_points cp WHERE cp.customer_id=c.id),0) points_balance,(SELECT COUNT(*) FROM invoices inv WHERE inv.customer_id=c.id AND inv.status<>'paid') unpaid_count FROM customers c LEFT JOIN packages pk ON pk.id=c.package_id WHERE $where ORDER BY c.id DESC LIMIT $per OFFSET $off",$params); return [$rows,$total,$page,$pages]; }
function customer_column_value($key,$r,$n){
    [$status,$statusClass]=customer_status_label($r['customer_status']??'active');
    switch($key){
        case 'no': return (string)$n;
        case 'actions': return customer_buttons($r);
        case 'customer_code': return '<b>'.e($r['customer_code']).'</b>';
        case 'name': return e($r['name']);
        case 'address': return e($r['address']);
        case 'phone': return e($r['phone']);
        case 'package_name': return e($r['package_name']?:'-');
        case 'speed': return e($r['speed']?:'-');
        case 'price': return ((int)($r['price']??0)>0 ? rp($r['price']) : '<span class="badge badge-info free-badge">FREE / Gratis</span>');
        case 'unpaid_count': return '<span class="badge '.(((int)($r['unpaid_count']??0))>0?'badge-warning':'badge-success').'">'.(int)($r['unpaid_count']??0).'</span>';
        case 'points_balance':
            return '<span class="point-badge"><i class="fas fa-star"></i> '.(int)($r['points_balance']??0).' Point</span>';
        case 'last_payment':
            if(empty($r['last_paid'])) return '<span class="text-muted">Belum ada</span>';
            $ts=strtotime($r['last_paid']); $date=$ts?date('d/m/Y H:i',$ts):$r['last_paid'];
            return '<div class="last-payment-cell"><b>'.rp($r['last_paid_amount']??0).'</b><small>'.e($date).' · '.e($r['last_paid_month']?:'-').' · '.e($r['last_paid_method']?:'-').'</small></div>';
        case 'area_name': return e($r['area_name']?:'-');
        case 'router_name': return e($r['router_name']?:'-');
        case 'connection_type': return 'PPPoE';
        case 'customer_status': return '<span class="badge '.$statusClass.'">'.$status.'</span>';
        case 'pppoe_username': return e($r['pppoe_username']?:$r['customer_code']);
        case 'customer_password': return e($r['customer_code']);
        case 'onu_name': return e($r['onu_name']?:'-');
        case 'registered_at': return e($r['registered_at']);
        case 'due_day': return e($r['due_day']);
    }
    return '-';
}
function render_column_manager($tableKey='customers'){
    $sets=v3_table_column_sets(); $defs=$sets[$tableKey]??[]; if(!$defs) return;
    $selected=v3_user_table_columns($tableKey); $return='index.php?'.http_build_query($_GET); $presets=v3_table_column_presets($tableKey);
    $selectedCount=count($selected); $totalCount=count($defs);
    echo '<details class="column-manager column-manager-pro column-manager-visible"><summary class="column-toolbar"><span class="column-toolbar-button"><i class="fas fa-sliders-h"></i> Atur kolom tabel</span><div><b>'.$selectedCount.'/'.$totalCount.' kolom tampil</b><span>Klik Atur kolom kalau ingin buka/tutup · tersimpan khusus admin: '.e($_SESSION['v3_user']['username']??'admin').'</span></div></summary><form method="post" class="column-manager-panel"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="save_table_columns"><input type="hidden" name="table_key" value="'.e($tableKey).'"><input type="hidden" name="return_to" value="'.e($return).'">';
    echo '<div class="column-manager-head"><div><b>Pilih, susun, lalu simpan tampilan tabel</b><small>Kolom paling atas akan tampil paling kiri. Pakai preset untuk setup cepat.</small></div><div class="column-counter"><span data-column-count>'.$selectedCount.'</span> kolom aktif</div></div>';
    echo '<div class="column-presets" data-column-presets>'; foreach($presets as $key=>$preset){ echo '<button type="button" class="column-preset" data-preset="'.e(implode(',',$preset['cols'])).'"><b>'.e($preset['label']).'</b><small>'.e($preset['desc']).'</small></button>'; } echo '</div>';
    echo '<div class="column-list" data-column-list>';
    $ordered=array_values(array_unique(array_merge($selected,array_keys($defs))));
    foreach($ordered as $key){ if(!isset($defs[$key])) continue; $label=$defs[$key][0]; $checked=in_array($key,$selected,true); $locked=in_array($key,['no','actions'],true); echo '<div class="column-choice" data-column-item data-key="'.e($key).'"><span class="drag-handle">☰</span><input type="hidden" class="column-hidden" name="columns[]" value="'.e($key).'" '.($checked?'':'disabled').'><label><input type="checkbox" class="column-check" '.($checked?'checked':'').' '.($locked?'disabled checked':'').'> <span>'.e($label).'</span></label><div class="column-move"><button type="button" class="btn btn-light btn-xs" data-move="up" title="Naik">↑</button><button type="button" class="btn btn-light btn-xs" data-move="down" title="Turun">↓</button></div></div>'; }
    echo '</div><div class="column-manager-actions"><button class="btn btn-info btn-sm"><i class="fas fa-save"></i> Simpan tampilan</button></form><form method="post" class="d-inline"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="reset_table_columns"><input type="hidden" name="table_key" value="'.e($tableKey).'"><input type="hidden" name="return_to" value="'.e($return).'"><button class="btn btn-secondary btn-sm"><i class="fas fa-undo"></i> Reset bawaan</button></form></div></details>';
}
