function unpaid_grand_summary(){ global $month,$q; $params=[$month]; $where="inv.invoice_month=? AND inv.status<>'paid'"; if($q!==''){ $where.=' AND (c.customer_code LIKE ? OR c.name LIKE ? OR c.address LIKE ? OR c.phone LIKE ? OR c.pppoe_username LIKE ? OR c.onu_name LIKE ?)'; for($i=0;$i<6;$i++)$params[]='%'.$q.'%'; } return q1("SELECT COUNT(DISTINCT c.id) customers, COUNT(inv.id) invoices, COALESCE(SUM(CASE WHEN inv.balance_amount IS NOT NULL THEN inv.balance_amount ELSE MAX(inv.amount-COALESCE(inv.paid_amount,0),0) END),0) total_due FROM invoices inv JOIN customers c ON c.id=inv.customer_id WHERE $where",$params); }
