function activity_detail_box($json,$title){
    if(!$json) return '';
    $data=json_decode($json,true); if(!is_array($data)) return '';
    $skip=['password_hash','password','csrf']; $items=[];
    foreach($data as $k=>$v){
        $lk=strtolower((string)$k); if(in_array($lk,$skip,true)||str_contains($lk,'password')) continue;
        if(is_array($v)||is_object($v)) $v=json_encode($v,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES);
        $items[]='<div><b>'.e($k).'</b>: '.e((string)$v).'</div>';
        if(count($items)>=18) break;
    }
    if(!$items) return '';
    return '<details class="activity-json"><summary>'.e($title).'</summary><div class="activity-json-body">'.implode('',$items).'</div></details>';
}

function v3_income_analysis_summary($selectedMonth){
    if(!preg_match('/^\d{4}-\d{2}$/',(string)$selectedMonth)) $selectedMonth=current_month();
    $invoiceValue=(int)scalar("SELECT COALESCE(SUM(amount),0) FROM invoices WHERE invoice_month=?",[$selectedMonth]);
    $invoiceCount=(int)scalar("SELECT COUNT(*) FROM invoices WHERE invoice_month=?",[$selectedMonth]);
    $paidValue=(int)scalar("SELECT COALESCE(SUM(amount),0) FROM payments WHERE invoice_month=?",[$selectedMonth]);
    $paidCustomers=(int)scalar("SELECT COUNT(DISTINCT customer_id) FROM payments WHERE invoice_month=?",[$selectedMonth]);
    $unpaidCount=(int)scalar("SELECT COUNT(*) FROM invoices WHERE invoice_month=? AND status<>'paid'",[$selectedMonth]);
    $unpaidValue=(int)scalar("SELECT COALESCE(SUM(CASE WHEN balance_amount IS NOT NULL THEN balance_amount ELSE MAX(amount-COALESCE(paid_amount,0),0) END),0) FROM invoices WHERE invoice_month=? AND status<>'paid'",[$selectedMonth]);
    $arrearsCount=(int)scalar("SELECT COUNT(*) FROM invoices WHERE invoice_month<? AND status<>'paid'",[$selectedMonth]);
    $arrearsCustomers=(int)scalar("SELECT COUNT(DISTINCT customer_id) FROM invoices WHERE invoice_month<? AND status<>'paid'",[$selectedMonth]);
    $arrearsValue=(int)scalar("SELECT COALESCE(SUM(CASE WHEN balance_amount IS NOT NULL THEN balance_amount ELSE MAX(amount-COALESCE(paid_amount,0),0) END),0) FROM invoices WHERE invoice_month<? AND status<>'paid'",[$selectedMonth]);
    $overpayRows=qall("SELECT c.id,c.customer_code,c.name,COALESCE(inv.invoice_month,pay.invoice_month) invoice_month,COALESCE(inv.amount,0) invoice_amount,COALESCE(SUM(pay.amount),0) paid_amount,(COALESCE(SUM(pay.amount),0)-COALESCE(inv.amount,0)) over_amount,COUNT(pay.id) trx_count FROM payments pay JOIN customers c ON c.id=pay.customer_id LEFT JOIN invoices inv ON inv.customer_id=pay.customer_id AND inv.invoice_month=pay.invoice_month WHERE pay.invoice_month=? GROUP BY pay.customer_id,pay.invoice_month HAVING over_amount>0 ORDER BY over_amount DESC,c.name LIMIT 100",[$selectedMonth]);
    $overpayValue=0; foreach($overpayRows as $r){ $overpayValue+=(int)$r['over_amount']; }
    $realization=$invoiceValue>0?round(($paidValue/$invoiceValue)*100,1):0;
    return ['month'=>$selectedMonth,'invoice_value'=>$invoiceValue,'invoice_count'=>$invoiceCount,'paid_value'=>$paidValue,'paid_customers'=>$paidCustomers,'unpaid_count'=>$unpaidCount,'unpaid_value'=>$unpaidValue,'arrears_count'=>$arrearsCount,'arrears_customers'=>$arrearsCustomers,'arrears_value'=>$arrearsValue,'overpay_rows'=>$overpayRows,'overpay_value'=>$overpayValue,'overpay_count'=>count($overpayRows),'realization'=>$realization];
}
function v3_month_range($from,$to){
    if(!preg_match('/^\d{4}-\d{2}$/',(string)$from)) $from=date('Y').'-01';
    if(!preg_match('/^\d{4}-\d{2}$/',(string)$to)) $to=current_month();
    if($from>$to){ $tmp=$from; $from=$to; $to=$tmp; }
    $out=[]; $cur=strtotime($from.'-01'); $end=strtotime($to.'-01'); $guard=0;
    while($cur!==false && $cur<=$end && $guard<36){ $out[]=date('Y-m',$cur); $cur=strtotime(date('Y-m-01',$cur).' +1 month'); $guard++; }
    return $out;
}

