?><script>window.initCollectionSearch=function(form){if(!form||form.dataset.collectionSearchReady)return;form.dataset.collectionSearchReady="1";const search=form.querySelector(".collection-live-search"),items=[...form.querySelectorAll(".collection-search-item")],checks=items.map(x=>x.querySelector("input[type=checkbox]")).filter(Boolean),selected=form.querySelector("[data-selected-count]"),visible=form.querySelector("[data-visible-count]"),footer=form.querySelector("[data-footer-selected]");function update(){const term=(search?.value||"").trim().toLowerCase();let shown=0;items.forEach(item=>{const ok=!term||(item.dataset.search||"").includes(term);item.hidden=!ok;if(ok)shown++});const count=checks.filter(x=>x.checked).length;if(selected)selected.textContent=count;if(visible)visible.textContent=shown;if(footer)footer.textContent=count;form.classList.toggle("has-selection",count>0)}search?.addEventListener("input",update);checks.forEach(x=>x.addEventListener("change",update));form.querySelectorAll("[data-select-visible]").forEach(b=>b.addEventListener("click",()=>{items.filter(x=>!x.hidden).forEach(x=>{const c=x.querySelector("input[type=checkbox]");if(c&&!c.disabled)c.checked=true});update()}));form.querySelector("[data-select-visible-check]")?.addEventListener("change",e=>{items.filter(x=>!x.hidden).forEach(x=>{const c=x.querySelector("input[type=checkbox]");if(c&&!c.disabled)c.checked=e.target.checked});update()});form.querySelectorAll("[data-clear-selection]").forEach(b=>b.addEventListener("click",()=>{checks.forEach(c=>c.checked=false);const all=form.querySelector("[data-select-visible-check]");if(all)all.checked=false;update()}));form.querySelectorAll(".collection-select-customer").forEach(b=>b.addEventListener("click",()=>{b.closest(".collection-customer-card")?.querySelectorAll("input[type=checkbox]:not(:disabled)").forEach(c=>c.checked=true);update()}));update()};document.addEventListener("DOMContentLoaded",()=>document.querySelectorAll("[data-selection-scope]").forEach(x=>window.initCollectionSearch(x.closest("form"))));</script><?php
